document.addEventListener("DOMContentLoaded",()=>{const e=window.location.origin,n=document.getElementById("signup-form"),t=document.getElementById("login-form"),o=document.getElementById("message"),s=(e,n=!1)=>{o.textContent=e,o.style.color=n?"red":"green"};n.addEventListener("submit",async n=>{n.preventDefault(),s("Processing registration...",!1);const t=document.getElementById("signup-username").value,o=document.getElementById("signup-password").value;try{const n=await fetch(`${e}/signup`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:t,password:o})}),r=await n.json();n.ok?(s(`Sign Up Success! ${r.message}`,!1),document.getElementById("signup-username").value="",document.getElementById("signup-password").value=""):s(`Sign Up Failed: ${r.message}`,!0)}catch(e){console.error("Network or server error:",e),s("Error connecting to server: Check backend (port 3000) is running.",!0)}}),t.addEventListener("submit",async n=>{n.preventDefault(),s("Attempting login...",!1);const t=document.getElementById("login-username").value,o=document.getElementById("login-password").value;try{const n=await fetch(`${e}/login`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:t,password:o})}),r=await n.json();n.ok?(s(`Login Success! ${r.message}`,!1),console.log("Authentication Data:",r)):s(`Login Failed: ${r.message}`,!0)}catch(e){console.error("Network or server error:",e),s("Error connecting to server: Check backend (port 3000) is running.",!0)}})});